  1	import { useState } from 'react';
  2	import { FormProvider, useForm, useWatch } from 'react-hook-form';
  3	import { useNavigate } from 'react-router-dom-v5-compat';
  4	import { getResourceUrl } from 'src/modules/Providers/utils/helpers/getResourceUrl';
  5	
  6	import { StorageMapModelRef } from '@kubev2v/types';
  7	import {
  8	  Alert,
  9	  AlertActionCloseButton,
 10	  AlertVariant,
 11	  Button,
 12	  ButtonVariant,
 13	  Flex,
 14	  FlexItem,
 15	  Form,
 16	  Split,
 17	  Stack,
 18	} from '@patternfly/react-core';
 19	import { CreationMethod } from '@utils/analytics/constants';
 20	import { useForkliftAnalytics } from '@utils/analytics/hooks/useForkliftAnalytics';
 21	import { useForkliftTranslation } from '@utils/i18n';
 22	
 23	import { defaultStorageMapping, StorageMapFieldId } from '../constants';
 24	
 25	import CreateStorageMapFieldTable from './fields/CreateStorageMapFieldTable';
 26	import MapNameField from './fields/MapNameField';
 27	import ProjectSelectField from './fields/ProjectSelectField';
 28	import SourceProviderField from './fields/SourceProviderField';
 29	import TargetProviderField from './fields/TargetProviderField';
 30	import { createStorageMap } from './utils/createStorageMap';
 31	import type { CreateStorageMapFormData } from './types';
 32	
 33	import './CreateStorageMapForm.style.scss';
 34	
 35	const CreateStorageMapForm: React.FC = () => {
 36	  const { t } = useForkliftTranslation();
 37	  const navigate = useNavigate();
 38	  const { trackEvent } = useForkliftAnalytics();
 39	
 40	  const form = useForm<CreateStorageMapFormData>({
 41	    defaultValues: { [StorageMapFieldId.StorageMap]: [defaultStorageMapping] },
 42	    mode: 'onChange',
 43	  });
 44	  const {
 45	    control,
 46	    formState: { isSubmitting, isValid },
 47	    getValues,
 48	    handleSubmit,
 49	  } = form;
 50	  const [createError, setCreateError] = useState<Error>();
 51	  const project = useWatch({
 52	    control,
 53	    name: StorageMapFieldId.Project,
 54	  });
 55	
 56	  const storageMapsListUrl = getResourceUrl({
 57	    namespace: project,
 58	    reference: StorageMapModelRef,
 59	  });
 60	
 61	  const onSubmit = async () => {
 62	    setCreateError(undefined);
 63	
 64	    const { mapName, sourceProvider, storageMap, targetProvider } = getValues();
 65	
 66	    const trackStorageMapEvent = (eventType: string, properties = {}) => {
 67	      trackEvent(eventType, { ...properties, creationMethod: CreationMethod.Form });
 68	    };
 69	
 70	    try {
 71	      const createdStorageMap = await createStorageMap({
 72	        mappings: storageMap,
 73	        name: mapName,
 74	        project,
 75	        sourceProvider,
 76	        targetProvider,
 77	        trackEvent: trackStorageMapEvent,
 78	      });
 79	
 80	      const createdStorageMapUrl = getResourceUrl({
 81	        name: createdStorageMap.metadata?.name,
 82	        namespace: createdStorageMap.metadata?.namespace,
 83	        reference: StorageMapModelRef,
 84	      });
 85	
 86	      // Navigate to the created storage map
 87	      navigate(createdStorageMapUrl);
 88	    } catch (error) {
 89	      setCreateError(error as Error);
 90	    }
 91	  };
 92	
 93	  return (
 94	    <FormProvider {...form}>
 95	      <Flex
 96	        direction={{ default: 'column' }}
 97	        justifyContent={{ default: 'justifyContentSpaceBetween' }}
 98	        alignItems={{ default: 'alignItemsStretch' }}
 99	        flexWrap={{ default: 'nowrap' }}
100	        spaceItems={{ default: 'spaceItemsLg' }}
101	        className="pf-v6-u-h-100"
102	      >
103	        <Form className="create-storage-map-form">
104	          <MapNameField />
105	          <ProjectSelectField />
106	          <SourceProviderField />
107	          <TargetProviderField />
108	          <CreateStorageMapFieldTable />
109	        </Form>
110	
111	        <FlexItem>
112	          <Stack hasGutter>
113	            {createError?.message && (
114	              <Alert
115	                variant={AlertVariant.danger}
116	                title={t('Error creating storage map')}
117	                actionClose={
118	                  <AlertActionCloseButton
119	                    onClose={() => {
120	                      setCreateError(undefined);
121	                    }}
122	                  />
123	                }
124	              >
125	                {createError.message}
126	              </Alert>
127	            )}
128	
129	            <Split hasGutter>
130	              <Button
131	                onClick={handleSubmit(onSubmit)}
132	                isDisabled={!isValid || isSubmitting}
133	                isLoading={isSubmitting}
134	              >
135	                {t('Create')}
136	              </Button>
137	
138	              <Button
139	                variant={ButtonVariant.secondary}
140	                onClick={() => {
141	                  navigate(storageMapsListUrl);
142	                }}
143	              >
144	                {t('Cancel')}
145	              </Button>
146	            </Split>
147	          </Stack>
148	        </FlexItem>
149	      </Flex>
150	    </FormProvider>
151	  );
152	};
153	
154	export default CreateStorageMapForm;

